#include <bits/stdc++.h>
using namespace std;
map<char,int> id;
int n,m,a[102],b[102],dp[102][102];
int g[5][5]=
{{5,-1,-2,-1,-3},
{-1,5,-3,-2,-4},
{-2,-3,5,-2,-2},
{-1,-2,-2,5,-1},
{-3,-4,-2,-1,0}};
string s;
int main(){
    id['A']=0;
    id['C']=1;
    id['G']=2;
    id['T']=3;
    scanf("%d",&n);
    cin>>s;
    for(int i=0;i<n;i++)
        a[i+1]=id[s[i]];
    scanf("%d",&m);
    cin>>s;
    for(int i=0;i<m;i++)
        b[i+1]=id[s[i]];
    for(int i=0;i<=n;i++)
        for(int j=0;j<=m;j++){
            if(i==0 && j==0)
                dp[i][j]=0;
            else if(i==0)
                dp[i][j]=dp[i][j-1]+g[b[j]][4];
            else if(j==0)
                dp[i][j]=dp[i-1][j]+g[a[i]][4];
            else
                dp[i][j]=max(dp[i-1][j-1]+g[a[i]][b[j]],max(dp[i][j-1]+g[b[j]][4],dp[i-1][j]+g[a[i]][4]));
        }
    printf("%d",dp[n][m]);
    return 0;
}
